1	import { readFileSync } from "node:fs";
2	import { quote, claim, cap, isKnownItemType, type Item } from "./claim-office.js";
3	
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: { itemType: string; amount: number }[] } };
6	type Step = QuoteStep | ClaimStep;
7	
8	type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Step[];
11	};
12	
13	type Policy = { items: Item[]; remainingCap: number };
14	type StepResult = Record<string, number>;
15	
16	type ScenarioState = {
17	  customer: { yearsWithMHPCO: number };
18	  policies: Policy[];
19	  previousContracts: number;
20	};
21	
22	const handleQuoteStep = (state: ScenarioState, step: QuoteStep): StepResult => {
23	  const premium = quote({
24	    customer: {
25	      yearsWithMHPCO: state.customer.yearsWithMHPCO,
26	      previousContracts: state.previousContracts,
27	    },
28	    items: step.items,
29	  });
30	  state.policies.push({ items: step.items, remainingCap: cap(step.items) });
31	  state.previousContracts += 1;
32	  return { premium };
33	};
34	
35	const handleClaimStep = (state: ScenarioState, step: ClaimStep): StepResult => {
36	  const policy = state.policies[step.policy];
37	  for (const damage of step.incident.damages) {
38	    if (!policy.items.some((item) => item.type === damage.itemType)) {
39	      process.stderr.write(`error: damage itemType "${damage.itemType}" not in policy\n`);
40	      process.exit(1);
41	    }
42	  }
43	  const result = claim({ policy, incident: step.incident });
44	  policy.remainingCap = result.remainingCap;
45	  return { payout: result.payout, remainingCap: result.remainingCap };
46	};
47	
48	const processStep = (state: ScenarioState, step: Step): StepResult =>
49	  step.op === "quote" ? handleQuoteStep(state, step) : handleClaimStep(state, step);
50	
51	const runScenario = (scenario: Scenario): StepResult[] => {
52	  const state: ScenarioState = {
53	    customer: scenario.customer,
54	    policies: [],
55	    previousContracts: 0,
56	  };
57	  return scenario.steps.map((step) => processStep(state, step));
58	};
59	
60	const findUnknownItemType = (scenario: Scenario): string | undefined => {
61	  for (const step of scenario.steps) {
62	    if (step.op !== "quote") continue;
63	    for (const item of step.items) {
64	      if (!isKnownItemType(item.type)) return item.type;
65	    }
66	  }
67	  return undefined;
68	};
69	
70	const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));
71	
72	const unknownType = findUnknownItemType(scenario);
73	if (unknownType !== undefined) {
74	  process.stderr.write(`error: unknown item type "${unknownType}"\n`);
75	  process.exit(1);
76	}
77	
78	process.stdout.write(JSON.stringify({ results: runScenario(scenario) }));
79

1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const CURSED_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const COMPONENT_BASE = 25;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	const CLAIM_DEDUCTIBLE = 100;
31	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
32	const CLAIM_HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
33	
34	const ITEM_BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	export const KNOWN_ITEM_TYPES: Set<string> = new Set(Object.keys(ITEM_BASE_PREMIUMS));
44	
45	export function isKnownItemType(type: string): boolean {
46	  return KNOWN_ITEM_TYPES.has(type);
47	}
48	
49	function isComponentType(type: string): boolean {
50	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
51	}
52	
53	function groupItemsByType(items: Item[]): Map<string, Item[]> {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type) ?? [];
57	    group.push(item);
58	    groups.set(item.type, group);
59	  }
60	  return groups;
61	}
62	
63	function totalSurchargeRate(item: Item): number {
64	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
65	  const highEnchantmentRate =
66	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
67	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
68	      : 0;
69	  return cursedRate + highEnchantmentRate;
70	}
71	
72	function calculateItemSurcharge(type: string, item: Item): number {
73	  const base = ITEM_BASE_PREMIUMS[type];
74	  return base * totalSurchargeRate(item);
75	}
76	
77	function calculateGroupBase(type: string, group: Item[]): number {
78	  if (isComponentType(type) && group.length === 3) {
79	    return COMPONENT_BLOCK_PREMIUM;
80	  }
81	  return group.length * ITEM_BASE_PREMIUMS[type];
82	}
83	
84	function calculatePolicyBase(items: Item[]): number {
85	  const groups = groupItemsByType(items);
86	  return Array.from(groups).reduce(
87	    (total, [type, group]) => total + calculateGroupBase(type, group),
88	    0
89	  );
90	}
91	
92	function calculateItemSurcharges(items: Item[]): number {
93	  return items.reduce(
94	    (total, item) => total + calculateItemSurcharge(item.type, item),
95	    0
96	  );
97	}
98	
99	function calculateLoyaltyDiscount(customer: Customer, policyBase: number): number {
100	  if (customer.yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
101	    return 0;
102	  }
103	  return policyBase * LOYALTY_DISCOUNT_RATE;
104	}
105	
106	function calculateFollowUpDiscount(customer: Customer, policyBase: number): number {
107	  const hasPreviousContracts = (customer.previousContracts ?? 0) >= 1;
108	  if (!hasPreviousContracts) {
109	    return 0;
110	  }
111	  return policyBase * FOLLOW_UP_DISCOUNT_RATE;
112	}
113	
114	function calculateFirstInsuranceSurcharge(policyBase: number): number {
115	  return policyBase * FIRST_INSURANCE_RATE;
116	}
117	
118	export type Damage = {
119	  itemType: string;
120	  amount: number;
121	};
122	
123	export type Incident = {
124	  cause: string;
125	  damages: Damage[];
126	};
127	
128	export type PolicyState = {
129	  items: Item[];
130	  remainingCap: number;
131	};
132	
133	export type ClaimInput = {
134	  policy: PolicyState;
135	  incident: Incident;
136	};
137	
138	export type ClaimResult = {
139	  payout: number;
140	  remainingCap: number;
141	};
142	
143	function isHighEnchantmentForClaim(item: Item | undefined): boolean {
144	  return (item?.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
145	}
146	
147	function calculateDamagePayout(damage: Damage, items: Item[]): number {
148	  const item = items.find((i) => i.type === damage.itemType);
149	  const adjustedDamage = isHighEnchantmentForClaim(item)
150	    ? damage.amount * CLAIM_HIGH_ENCHANTMENT_PAYOUT_RATE
151	    : damage.amount;
152	  return Math.max(adjustedDamage - CLAIM_DEDUCTIBLE, 0);
153	}
154	
155	function sumDamagePayouts(damages: Damage[], items: Item[]): number {
156	  return damages.reduce(
157	    (total, damage) => total + calculateDamagePayout(damage, items),
158	    0
159	  );
160	}
161	
162	function capPayout(payout: number, remainingCap: number): number {
163	  return Math.min(payout, remainingCap);
164	}
165	
166	export function claim(input: ClaimInput): ClaimResult {
167	  const rawPayout = Math.floor(sumDamagePayouts(input.incident.damages, input.policy.items));
168	  const payout = capPayout(rawPayout, input.policy.remainingCap);
169	  return { payout, remainingCap: input.policy.remainingCap - payout };
170	}
171	
172	const ITEM_INSURANCE_VALUES: Record<string, number> = {
173	  sword: 1000,
174	  amulet: 600,
175	  staff: 800,
176	  potion: 400,
177	  rune: 250,
178	  moonstone: 250,
179	};
180	
181	const CAP_MULTIPLIER = 2;
182	
183	export function insuranceSum(items: Item[]): number {
184	  return items.reduce((total, item) => total + ITEM_INSURANCE_VALUES[item.type], 0);
185	}
186	
187	export function cap(items: Item[]): number {
188	  return CAP_MULTIPLIER * insuranceSum(items);
189	}
190	
191	export function quote(input: QuoteInput): number {
192	  const policyBase = calculatePolicyBase(input.items);
193	  const itemSurcharges = calculateItemSurcharges(input.items);
194	  const firstInsuranceSurcharge = calculateFirstInsuranceSurcharge(policyBase);
195	  const loyaltyDiscount = calculateLoyaltyDiscount(input.customer, policyBase);
196	  const followUpDiscount = calculateFollowUpDiscount(input.customer, policyBase);
197	  return Math.ceil(
198	    policyBase +
199	      itemSurcharges +
200	      firstInsuranceSurcharge +
201	      PROCESSING_FEE -
202	      loyaltyDiscount -
203	      followUpDiscount
204	  );
205	}
